{
  "openapi": "3.0.3",
  "info": {
    "title": "Agent HAL Read-Only MCP API",
    "description": "Read-only API surface for Agent HAL, exposed via AgentCore Gateway as MCP tools. Provides visibility into agent runs, statistics, project configuration, and ticket reviews.",
    "version": "1.0.0"
  },
  "servers": [
    {
      "url": "https://{apiId}.execute-api.eu-west-1.amazonaws.com/{stage}",
      "description": "Agent HAL Admin API (private)",
      "variables": {
        "apiId": {
          "description": "API Gateway REST API ID"
        },
        "stage": {
          "default": "prod",
          "enum": ["dev", "prod"]
        }
      }
    }
  ],
  "paths": {
    "/api/runs": {
      "get": {
        "operationId": "listRuns",
        "summary": "List recent agent runs",
        "description": "Returns paginated list of agent runs. Supports search by Jira ticket, project key, or GitHub org/repo, and filtering by trigger type.",
        "parameters": [
          {
            "name": "page",
            "in": "query",
            "description": "Page number (50 runs per page)",
            "schema": { "type": "integer", "default": 1, "minimum": 1 }
          },
          {
            "name": "q",
            "in": "query",
            "description": "Search query. Supports: 'ORG/REPO' (GitHub), 'ABC-123' (Jira ticket), 'ABC' (project key)",
            "schema": { "type": "string" }
          },
          {
            "name": "type",
            "in": "query",
            "description": "Filter by trigger type",
            "schema": {
              "type": "string",
              "enum": ["ticket", "pr-fix", "cron", "ticket-review", "merge-conflict", "mention"]
            }
          }
        ],
        "responses": {
          "200": {
            "description": "Paginated list of runs",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "runs": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/RunSummary" }
                    },
                    "totalCount": { "type": "integer" },
                    "totalPages": { "type": "integer" },
                    "page": { "type": "integer" }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/runs/{runId}": {
      "get": {
        "operationId": "getRun",
        "summary": "Get details for a single run",
        "description": "Returns full details for an agent run including error info, session state, review history, and skill review outcomes.",
        "parameters": [
          {
            "name": "runId",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "Run detail",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "run": { "$ref": "#/components/schemas/RunDetail" }
                  }
                }
              }
            }
          },
          "404": { "description": "Run not found" }
        }
      }
    },
    "/api/runs/{runId}/log": {
      "get": {
        "operationId": "getRunLog",
        "summary": "Get parsed log entries for a run",
        "description": "Returns human-readable log entries parsed from the run's NDJSON log file in S3.",
        "parameters": [
          {
            "name": "runId",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "Parsed log entries",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "entries": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "timestamp": { "type": "string", "format": "date-time" },
                          "message": { "type": "string" },
                          "extra": { "type": "object" }
                        }
                      }
                    }
                  }
                }
              }
            }
          },
          "404": { "description": "Log file not found" }
        }
      }
    },
    "/api/runs/{runId}/live-logs": {
      "get": {
        "operationId": "getRunLiveLogs",
        "summary": "Get live log entries for a running agent",
        "description": "Returns live log entries streamed from DynamoDB for an in-progress run. Supports polling with a 'since' timestamp.",
        "parameters": [
          {
            "name": "runId",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          },
          {
            "name": "since",
            "in": "query",
            "description": "Only return entries after this timestamp (epoch ms)",
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "Live log entries",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "entries": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "timestamp": { "type": "number" },
                          "message": { "type": "string" }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/runs/{runId}/reviews": {
      "get": {
        "operationId": "listRunReviews",
        "summary": "List skill review files for a run",
        "description": "Returns the names of available skill review markdown files for a given run.",
        "parameters": [
          {
            "name": "runId",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "List of review file names",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "reviews": {
                      "type": "array",
                      "items": { "type": "string" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/runs/{runId}/reviews/{name}": {
      "get": {
        "operationId": "getRunReview",
        "summary": "Get a skill review file",
        "description": "Returns the markdown content of a specific skill review file for a run.",
        "parameters": [
          {
            "name": "runId",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          },
          {
            "name": "name",
            "in": "path",
            "required": true,
            "description": "Review file name (e.g. 'security-review')",
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "Review markdown content",
            "content": {
              "text/markdown": {
                "schema": { "type": "string" }
              }
            }
          },
          "404": { "description": "Review file not found" }
        }
      }
    },
    "/api/stats": {
      "get": {
        "operationId": "getStats",
        "summary": "Get aggregated run statistics by project",
        "description": "Returns aggregated statistics per Jira project including run counts, PR creation rates, costs, success rates, and quality metrics.",
        "parameters": [
          {
            "name": "weeks",
            "in": "query",
            "description": "Time range filter",
            "schema": {
              "type": "string",
              "enum": ["4", "8", "all"],
              "default": "all"
            }
          }
        ],
        "responses": {
          "200": {
            "description": "Aggregated stats by project",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "stats": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/ProjectStats" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/stats/trends": {
      "get": {
        "operationId": "getStatsTrends",
        "summary": "Get weekly trend data",
        "description": "Returns weekly trend data showing tickets, users, PRs created, costs, and success rates over time.",
        "parameters": [
          {
            "name": "weeks",
            "in": "query",
            "description": "Number of weeks to include",
            "schema": {
              "type": "string",
              "enum": ["4", "8", "all"],
              "default": "4"
            }
          },
          {
            "name": "projectKey",
            "in": "query",
            "description": "Filter to a single Jira project",
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "Weekly trend data",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "weeks": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/WeeklyTrend" }
                    },
                    "projectKeys": {
                      "type": "array",
                      "items": { "type": "string" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/stats/snapshot": {
      "get": {
        "operationId": "getStatsSnapshot",
        "summary": "Get cached stats snapshot",
        "description": "Returns a previously cached stats snapshot for a project. Snapshots are updated whenever the stats page is loaded.",
        "parameters": [
          {
            "name": "project",
            "in": "query",
            "description": "Project key or '_all' for aggregate",
            "schema": { "type": "string", "default": "_all" }
          },
          {
            "name": "weeks",
            "in": "query",
            "description": "Number of weeks",
            "schema": { "type": "string", "default": "4" }
          }
        ],
        "responses": {
          "200": {
            "description": "Cached stats snapshot",
            "content": {
              "application/json": {
                "schema": { "$ref": "#/components/schemas/StatsSnapshot" }
              }
            }
          },
          "404": { "description": "Snapshot not found" }
        }
      }
    },
    "/api/projects": {
      "get": {
        "operationId": "listProjects",
        "summary": "List all project configurations",
        "description": "Returns all configured Jira-to-GitHub project mappings, sorted alphabetically by project key.",
        "responses": {
          "200": {
            "description": "List of project configs",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "projects": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/ProjectConfig" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/cron-jobs": {
      "get": {
        "operationId": "listCronJobs",
        "summary": "List all scheduled cron jobs",
        "description": "Returns all cron job definitions including schedule, target repos, and active run status.",
        "responses": {
          "200": {
            "description": "List of cron jobs",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "jobs": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/CronJob" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/cron-jobs/{jobId}/runs": {
      "get": {
        "operationId": "listCronJobRuns",
        "summary": "List runs for a specific cron job",
        "description": "Returns all agent runs triggered by a specific cron job, sorted by creation date descending.",
        "parameters": [
          {
            "name": "jobId",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "List of runs for the cron job",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "runs": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/RunSummary" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/audit-log": {
      "get": {
        "operationId": "getAuditLog",
        "summary": "List recent audit trail entries",
        "description": "Returns the most recent 200 audit log entries. Requires admin role.",
        "responses": {
          "200": {
            "description": "Audit log entries",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "logs": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/AuditLogEntry" }
                    }
                  }
                }
              }
            }
          },
          "403": { "description": "Admin role required" }
        }
      }
    },
    "/api/ticket-reviews": {
      "get": {
        "operationId": "listTicketReviews",
        "summary": "List top-level ticket reviews",
        "description": "Returns the 100 most recent top-level ticket reviews (no child reviews), sorted by creation date descending.",
        "responses": {
          "200": {
            "description": "List of ticket reviews",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "reviews": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/TicketReviewSummary" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/ticket-reviews/{id}": {
      "get": {
        "operationId": "getTicketReview",
        "summary": "Get a single ticket review",
        "description": "Returns full details for a ticket review including the review markdown content.",
        "parameters": [
          {
            "name": "id",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "Ticket review detail",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "review": { "$ref": "#/components/schemas/TicketReviewDetail" }
                  }
                }
              }
            }
          },
          "404": { "description": "Review not found" }
        }
      }
    },
    "/api/ticket-reviews/{id}/children": {
      "get": {
        "operationId": "listTicketReviewChildren",
        "summary": "Get child reviews for a group review",
        "description": "Returns child reviews for epic/sprint/label group reviews.",
        "parameters": [
          {
            "name": "id",
            "in": "path",
            "required": true,
            "schema": { "type": "string" }
          }
        ],
        "responses": {
          "200": {
            "description": "Child reviews",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "children": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/TicketReviewSummary" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/config": {
      "get": {
        "operationId": "getConfig",
        "summary": "Get global configuration",
        "description": "Returns global Agent HAL configuration including failsafe mode status.",
        "responses": {
          "200": {
            "description": "Global config",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "config": { "$ref": "#/components/schemas/GlobalConfig" }
                  }
                }
              }
            }
          }
        }
      }
    },
    "/api/prompts": {
      "get": {
        "operationId": "listPrompts",
        "summary": "List agent prompts",
        "description": "Returns all configured agent system prompts grouped by execution stage.",
        "responses": {
          "200": {
            "description": "Agent prompts",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "prompts": {
                      "type": "array",
                      "items": { "$ref": "#/components/schemas/Prompt" }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  },
  "components": {
    "schemas": {
      "RunSummary": {
        "type": "object",
        "properties": {
          "runId": { "type": "string" },
          "jiraTicketKey": { "type": "string" },
          "jiraTicketSummary": { "type": "string" },
          "projectKey": { "type": "string" },
          "status": {
            "type": "string",
            "enum": ["SUBMITTED", "RUNNING", "REVIEWING", "COMPLETED", "FAILED", "TIMED_OUT", "TERMINATED", "STALE", "SPOT_INTERRUPTED", "KILL_REQUESTED"]
          },
          "createdAt": { "type": "string", "format": "date-time" },
          "updatedAt": { "type": "string", "format": "date-time" },
          "jobId": { "type": "string" },
          "model": { "type": "string" },
          "repoUrl": { "type": "string" },
          "prUrl": { "type": "string" },
          "branch": { "type": "string" },
          "runSummary": { "type": "string" },
          "totalCostUsd": { "type": "number" },
          "totalInputTokens": { "type": "integer" },
          "totalOutputTokens": { "type": "integer" },
          "creationCostUsd": { "type": "number" },
          "reviewCostUsd": { "type": "number" },
          "triggerType": { "type": "string", "enum": ["ticket", "pr-fix", "cron", "ticket-review", "merge-conflict", "mention"] },
          "operationType": { "type": "string" },
          "cronJobId": { "type": "string" },
          "rating": { "type": "string", "enum": ["up", "down"] },
          "agentVersion": { "type": "string" },
          "mergedAt": { "type": "string", "format": "date-time" },
          "mergedBy": { "type": "string" },
          "mergeSha": { "type": "string" },
          "ticketQualityScore": { "type": "number" },
          "hadHumanCommits": { "type": "boolean" },
          "humanCommitCount": { "type": "integer" },
          "hadHumanGuidanceOnPr": { "type": "boolean" },
          "humanPrCommentCount": { "type": "integer" },
          "hadJiraGuidanceAfterPr": { "type": "boolean" },
          "prClosedWithoutMerge": { "type": "boolean" }
        }
      },
      "RunDetail": {
        "allOf": [
          { "$ref": "#/components/schemas/RunSummary" },
          {
            "type": "object",
            "properties": {
              "error": { "type": "string" },
              "question": { "type": "string" },
              "sessionId": { "type": "string" },
              "lastHeartbeat": { "type": "string", "format": "date-time" },
              "creationNumTurns": { "type": "integer" },
              "reviewNumTurns": { "type": "integer" },
              "supersededByRunId": { "type": "string" },
              "rerunOfRunId": { "type": "string" },
              "reviewRounds": { "type": "integer" },
              "reviewOutcome": { "type": "string" },
              "reviewHistory": { "type": "array", "items": { "type": "object" } },
              "skillReviews": { "type": "array", "items": { "type": "string" } },
              "skillReviewOutcomes": { "type": "object" },
              "ticketQualityMarkdown": { "type": "string" },
              "safetyOverride": { "type": "string" }
            }
          }
        ]
      },
      "ProjectStats": {
        "type": "object",
        "properties": {
          "projectKey": { "type": "string" },
          "ticketsWorkedOn": { "type": "integer" },
          "totalRuns": { "type": "integer" },
          "prsCreated": { "type": "integer" },
          "totalCostUsd": { "type": "number" },
          "completedRuns": { "type": "integer" },
          "terminalRuns": { "type": "integer" },
          "ratingUp": { "type": "integer" },
          "ratingDown": { "type": "integer" },
          "totalRated": { "type": "integer" },
          "fullSuccess": { "type": "integer" },
          "partialSuccess": { "type": "integer" },
          "failure": { "type": "integer" },
          "stale": { "type": "integer" },
          "successRate": { "type": "number" }
        }
      },
      "WeeklyTrend": {
        "type": "object",
        "properties": {
          "weekStart": { "type": "string", "description": "YYYY-MM-DD" },
          "weekEnd": { "type": "string", "description": "YYYY-MM-DD" },
          "tickets": { "type": "integer" },
          "users": { "type": "integer" },
          "prsCreated": { "type": "integer" },
          "totalRuns": { "type": "integer" },
          "totalCostUsd": { "type": "number" },
          "fullSuccess": { "type": "integer" },
          "partialSuccess": { "type": "integer" },
          "stale": { "type": "integer" },
          "successRate": { "type": "number" }
        }
      },
      "StatsSnapshot": {
        "type": "object",
        "properties": {
          "projectKey": { "type": "string" },
          "weeks": { "type": "string" },
          "completedRuns": { "type": "integer" },
          "terminalRuns": { "type": "integer" },
          "fullSuccess": { "type": "integer" },
          "partialSuccess": { "type": "integer" },
          "failure": { "type": "integer" },
          "stale": { "type": "integer" },
          "totalRuns": { "type": "integer" },
          "prsCreated": { "type": "integer" },
          "successRate": { "type": "number" },
          "updatedAt": { "type": "string", "format": "date-time" },
          "formulaVersion": { "type": "string" }
        }
      },
      "ProjectConfig": {
        "type": "object",
        "properties": {
          "projectKey": { "type": "string" },
          "githubOrg": { "type": "string" },
          "defaultBranch": { "type": "string", "default": "main" },
          "model": { "type": "string" }
        }
      },
      "CronJob": {
        "type": "object",
        "properties": {
          "jobId": { "type": "string", "format": "uuid" },
          "cronExpression": { "type": "string" },
          "operationType": { "type": "string" },
          "repoUrls": { "type": "array", "items": { "type": "string" } },
          "description": { "type": "string" },
          "projectKey": { "type": "string" },
          "enabled": { "type": "boolean" },
          "nextRunAt": { "type": "string", "format": "date-time" },
          "createdAt": { "type": "string", "format": "date-time" },
          "updatedAt": { "type": "string", "format": "date-time" },
          "lastRunAt": { "type": "string", "format": "date-time" },
          "activeRuns": {
            "type": "object",
            "additionalProperties": {
              "type": "object",
              "properties": {
                "runId": { "type": "string" },
                "startedAt": { "type": "string", "format": "date-time" }
              }
            }
          },
          "branch": { "type": "string", "default": "main" },
          "datadogService": { "type": "string" }
        }
      },
      "AuditLogEntry": {
        "type": "object",
        "properties": {
